const ISLAMIC_INFO = {"friday": {"title_ar": "يوم الجمعة - سيد الأيام", "title_es": "Viernes - El Señor de los Días", "virtue_ar": "يوم الجمعة سيّد الأيام عند الله، فيه ساعة لا يوافقها مسلم يدعو الله إلا استجاب له، وتُغفر فيه الذنوب من جمعة إلى جمعة.", "virtue_es": "El viernes es el mejor de los días ante Allah. En él hay una hora en que si un musulmán pide a Allah, Le será concedido; y los pecados son perdonados de un viernes a otro.", "quote_ar": "«خَيْرُ يَوْمٍ طَلَعَتْ عَلَيْهِ الشَّمْسُ يَوْمُ الْجُمُعَةِ، فِيهِ خُلِقَ آدَمُ، وَفِيهِ أُدْخِلَ الْجَنَّةَ، وَفِيهِ أُخْرِجَ مِنْهَا»", "quote_es": "«El mejor día sobre el que sale el sol es el viernes: en él fue creado Adán, en él entró al Paraíso y en él salió de él».", "ref": "رواه مسلم · Sahih Muslim"}, "white_days": {"title_ar": "الأيام البيض (13-14-15 من كل شهر هجري)", "title_es": "Días Blancos (13, 14, 15 de cada mes Hijri)", "virtue_ar": "صيام الأيام البيض من السنن المؤكدة عن النبي ﷺ، يعدل صيام ثلاثة أيام منها صيام الشهر، فإذا داومتَ عليها كان كصيام الدهر.", "virtue_es": "Ayunar los Días Blancos es una Sunna establecida del Profeta ﷺ. Tres días de ayuno equivalen a ayunar el mes; quien los mantiene es como si ayunara todo el año.", "quote_ar": "«صِيَامُ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ صِيَامُ الدَّهْرِ، أَيَّامُ الْبِيضِ: صَبِيحَةَ ثَلَاثَ عَشْرَةَ، وَأَرْبَعَ عَشْرَةَ، وَخَمْسَ عَشْرَةَ»", "quote_es": "«Ayunar tres días de cada mes equivale a ayunar todo el tiempo: los días blancos, las mañanas del 13, 14 y 15».", "ref": "رواه النسائي · An-Nasa'i"}, "isra_miraj": {"title_ar": "ليلة الإسراء والمعراج", "title_es": "Al-Isra wal-Mi'raj (Viaje Nocturno y Ascensión)", "virtue_ar": "في هذه الليلة أَسْرَى الله بنبيه محمد ﷺ من المسجد الحرام إلى المسجد الأقصى، ثم عُرج به إلى السماوات العلا، وفُرضت في تلك الليلة الصلوات الخمس.", "virtue_es": "En esta noche Allah llevó a Su Profeta Muhammad ﷺ desde la Mezquita Sagrada hasta la Mezquita al-Aqsa, y luego lo elevó a los cielos. Fueron prescritas las cinco oraciones diarias.", "quote_ar": "{سُبْحَانَ الَّذِي أَسْرَى بِعَبْدِهِ لَيْلًا مِنَ الْمَسْجِدِ الْحَرَامِ إِلَى الْمَسْجِدِ الْأَقْصَى الَّذِي بَارَكْنَا حَوْلَهُ لِنُرِيَهُ مِنْ آيَاتِنَا}", "quote_es": "«¡Glorificado sea Quien hizo viajar de noche a Su siervo desde la Mezquita Sagrada hasta la Mezquita al-Aqsa, cuyos alrededores hemos bendecido, para mostrarle parte de Nuestros signos!»", "ref": "الإسراء: 1 · Corán 17:1"}, "nisf_shaban": {"title_ar": "ليلة النصف من شعبان", "title_es": "Mitad de Sha'ban", "virtue_ar": "ليلة مباركة يُستحب فيها الإكثار من الطاعة والاستغفار، وصيام يومها من جملة الأيام البيض المستحبة.", "virtue_es": "Una noche bendita en la que se recomienda multiplicar la adoración y el arrepentimiento, y ayunar el día como parte de los Días Blancos.", "quote_ar": "«إِنَّ اللَّهَ لَيَطَّلِعُ فِي لَيْلَةِ النِّصْفِ مِنْ شَعْبَانَ، فَيَغْفِرُ لِجَمِيعِ خَلْقِهِ، إِلَّا لِمُشْرِكٍ أَوْ مُشَاحِنٍ»", "quote_es": "«Allah desciende [con Su Misericordia] en la noche de la mitad de Sha'ban y perdona a toda Su creación, excepto al que asocia a otro con Él o al que guarda rencor».", "ref": "رواه ابن ماجه · Ibn Majah"}, "ramadan_start": {"title_ar": "أول شهر رمضان المبارك", "title_es": "Primer día del bendito mes de Ramadán", "virtue_ar": "يبدأ هنا شهر القرآن، شهر الصيام والقيام والرحمة والمغفرة والعتق من النار. تُفتح فيه أبواب الجنة وتُغلق أبواب النار وتُصفّد الشياطين.", "virtue_es": "Comienza el mes del Corán, del ayuno, las oraciones nocturnas, la misericordia, el perdón y la liberación del Fuego. Las puertas del Paraíso se abren, las del Infierno se cierran y los demonios son encadenados.", "quote_ar": "{شَهْرُ رَمَضَانَ الَّذِي أُنْزِلَ فِيهِ الْقُرْآنُ هُدًى لِلنَّاسِ وَبَيِّنَاتٍ مِنَ الْهُدَىٰ وَالْفُرْقَانِ}", "quote_es": "«El mes de Ramadán, en el cual fue revelado el Corán como guía para la humanidad y como pruebas claras de la guía y del criterio».", "ref": "البقرة: 185 · Corán 2:185"}, "ramadan": {"title_ar": "يوم من أيام رمضان المبارك", "title_es": "Día del bendito mes de Ramadán", "virtue_ar": "صيام رمضان ركن من أركان الإسلام، يُكفِّر الله به ما تقدم من الذنوب لمن صامه إيماناً واحتساباً، وتُضاعَف فيه الحسنات.", "virtue_es": "El ayuno de Ramadán es uno de los pilares del Islam; Allah perdona los pecados pasados de quien lo ayuna con fe y esperanza de recompensa, y las buenas acciones se multiplican.", "quote_ar": "«مَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ»", "quote_es": "«Quien ayune Ramadán con fe y esperando la recompensa, sus pecados pasados serán perdonados».", "ref": "متفق عليه · Bukhari y Muslim"}, "last_ten_ramadan": {"title_ar": "العشر الأواخر من رمضان", "title_es": "Los últimos diez días de Ramadán", "virtue_ar": "أعظم عشرٍ في أعظم شهر؛ فيها ليلة القدر التي هي خير من ألف شهر. كان النبي ﷺ يجتهد فيها ما لا يجتهد في غيرها، ويعتكف فيها.", "virtue_es": "Los diez más grandes del mes más grande; en ellos está Laylat al-Qadr, mejor que mil meses. El Profeta ﷺ se esforzaba en ellos como en ningún otro momento y hacía i'tikaf (retiro).", "quote_ar": "«كَانَ النَّبِيُّ ﷺ إِذَا دَخَلَ الْعَشْرُ شَدَّ مِئْزَرَهُ، وَأَحْيَا لَيْلَهُ، وَأَيْقَظَ أَهْلَهُ»", "quote_es": "«Cuando comenzaban los últimos diez días, el Profeta ﷺ ceñía su cintura (para la adoración), pasaba la noche en vela y despertaba a su familia».", "ref": "متفق عليه · Bukhari y Muslim"}, "laylat_qadr": {"title_ar": "ليلة القدر", "title_es": "Laylat al-Qadr (Noche del Decreto)", "virtue_ar": "ليلة خير من ألف شهر، تتنزل فيها الملائكة والروح، يُغفر فيها للقائم إيماناً واحتساباً. تُلتمس في الوتر من العشر الأواخر.", "virtue_es": "Una noche mejor que mil meses; en ella descienden los ángeles y el Espíritu. Quien la pase en oración con fe y esperando la recompensa será perdonado. Se busca en las noches impares de los últimos diez.", "quote_ar": "{لَيْلَةُ الْقَدْرِ خَيْرٌ مِنْ أَلْفِ شَهْرٍ * تَنَزَّلُ الْمَلَائِكَةُ وَالرُّوحُ فِيهَا بِإِذْنِ رَبِّهِمْ مِنْ كُلِّ أَمْرٍ * سَلَامٌ هِيَ حَتَّىٰ مَطْلَعِ الْفَجْرِ}", "quote_es": "«La Noche del Decreto es mejor que mil meses. En ella descienden los ángeles y el Espíritu, con permiso de su Señor, para cumplir todo asunto. Es paz hasta el despuntar del alba».", "ref": "القدر: 3-5 · Corán 97:3-5"}, "eid_fitr": {"title_ar": "عيد الفطر المبارك", "title_es": "Eid al-Fitr Bendito", "virtue_ar": "أول أيام شوال، يوم فرحة المؤمنين بإتمام صيامهم. يُسنّ التكبير، والاغتسال، ولبس أحسن الثياب، وأداء صلاة العيد، وإخراج زكاة الفطر قبلها.", "virtue_es": "El primer día de Shawwal, día de alegría de los creyentes por completar su ayuno. Se recomienda el Takbir, el baño, vestir las mejores ropas, rezar la oración del Eid y dar el Zakat al-Fitr antes.", "quote_ar": "{وَلِتُكْمِلُوا الْعِدَّةَ وَلِتُكَبِّرُوا اللَّهَ عَلَىٰ مَا هَدَاكُمْ وَلَعَلَّكُمْ تَشْكُرُونَ}", "quote_es": "«Y para que completéis el número [de días] y para que glorifiquéis a Allah por haberos guiado, y para que seáis agradecidos».", "ref": "البقرة: 185 · Corán 2:185"}, "six_shawwal": {"title_ar": "ست من شوال", "title_es": "Seis días de Shawwal", "virtue_ar": "صيام ستة أيام من شوال بعد رمضان من السنن العظيمة، يعدل صيامُ رمضانَ معها صيامَ الدهر كله.", "virtue_es": "Ayunar seis días de Shawwal tras Ramadán es una gran Sunna; junto con el ayuno de Ramadán equivale al ayuno de todo el año.", "quote_ar": "«مَنْ صَامَ رَمَضَانَ ثُمَّ أَتْبَعَهُ سِتًّا مِنْ شَوَّالٍ كَانَ كَصِيَامِ الدَّهْرِ»", "quote_es": "«Quien ayune Ramadán y lo siga con seis días de Shawwal, es como si hubiera ayunado todo el tiempo».", "ref": "رواه مسلم · Sahih Muslim"}, "ten_dhulhijjah": {"title_ar": "عشر ذي الحجة", "title_es": "Los diez días de Dhul-Hijjah", "virtue_ar": "أفضل أيام الدنيا، أقسم الله بها في كتابه. العمل الصالح فيها أحب إلى الله من سواها. يُستحب فيها الصيام والذكر والتكبير والصدقة.", "virtue_es": "Los mejores días del mundo; Allah juró por ellos en Su Libro. Las buenas acciones en ellos son más amadas por Allah que en cualquier otro tiempo. Se recomiendan el ayuno, el dhikr, el Takbir y la caridad.", "quote_ar": "{وَالْفَجْرِ * وَلَيَالٍ عَشْرٍ} — «مَا مِنْ أَيَّامٍ الْعَمَلُ الصَّالِحُ فِيهِنَّ أَحَبُّ إِلَى اللَّهِ مِنْ هَذِهِ الْأَيَّامِ الْعَشْرِ»", "quote_es": "«¡Por el alba! ¡Y por las diez noches!» — «No hay días en que las buenas acciones sean más amadas por Allah que estos diez días».", "ref": "الفجر:1-2 · البخاري · Corán 89:1-2; Bukhari"}, "arafah": {"title_ar": "يوم عرفة", "title_es": "Día de Arafat", "virtue_ar": "أفضل أيام السنة، يوم إكمال الدين، يُكفّر الله بصيامه ذنوب سنتين: الماضية والآتية لغير الحاج. وفيه يباهي الله بأهل الموقف ملائكته.", "virtue_es": "El mejor día del año, día de la perfección del Dīn. Ayunarlo borra los pecados de dos años: el anterior y el siguiente, para quien no está en peregrinación. Allah se enorgullece de los peregrinos ante Sus ángeles.", "quote_ar": "«صِيَامُ يَوْمِ عَرَفَةَ، أَحْتَسِبُ عَلَى اللَّهِ أَنْ يُكَفِّرَ السَّنَةَ الَّتِي قَبْلَهُ وَالسَّنَةَ الَّتِي بَعْدَهُ»", "quote_es": "«El ayuno del día de Arafat — espero de Allah que borre los pecados del año anterior y del siguiente».", "ref": "رواه مسلم · Sahih Muslim"}, "eid_adha": {"title_ar": "عيد الأضحى المبارك", "title_es": "Eid al-Adha Bendito", "virtue_ar": "يوم النحر، أعظم أيام السنة عند الله. يُسنّ فيه التكبير وصلاة العيد والأضحية إحياءً لسنة إبراهيم عليه السلام.", "virtue_es": "El día del sacrificio, el más grande del año ante Allah. Se recomiendan el Takbir, la oración del Eid y el sacrificio (Udhiyah) reviviendo la Sunna de Ibrahim (la paz sea con él).", "quote_ar": "{فَصَلِّ لِرَبِّكَ وَانْحَرْ * إِنَّ شَانِئَكَ هُوَ الْأَبْتَرُ}", "quote_es": "«Reza, pues, a tu Señor y sacrifica. En verdad, quien te odia será el privado [de todo bien]».", "ref": "الكوثر: 2-3 · Corán 108:2-3"}, "tashreeq": {"title_ar": "أيام التشريق", "title_es": "Días de Tashriq", "virtue_ar": "أيام أكل وشرب وذكر لله. يُسنّ فيها التكبير دبر الصلوات، ولا يجوز صيامها إلا لمن لم يجد الهدي في الحج.", "virtue_es": "Días de comer, beber y recordar a Allah. Se recomienda el Takbir tras las oraciones, y no se ayunan excepto para quien no encontró el sacrificio en el Hajj.", "quote_ar": "«أَيَّامُ التَّشْرِيقِ أَيَّامُ أَكْلٍ وَشُرْبٍ وَذِكْرٍ لِلَّهِ»", "quote_es": "«Los días de Tashriq son días de comer, beber y recordar a Allah».", "ref": "رواه مسلم · Sahih Muslim"}, "hijri_new_year": {"title_ar": "رأس السنة الهجرية 1448هـ", "title_es": "Año Nuevo Hijri 1448", "virtue_ar": "ذكرى هجرة النبي ﷺ من مكة إلى المدينة، وبها بدأ التقويم الإسلامي. مناسبة للتأمل في معاني التضحية والثبات على الحق.", "virtue_es": "Conmemora la Hégira del Profeta ﷺ de La Meca a Medina, comienzo del calendario islámico. Ocasión para reflexionar sobre el sacrificio y la firmeza en la verdad.", "quote_ar": "{إِلَّا تَنْصُرُوهُ فَقَدْ نَصَرَهُ اللَّهُ إِذْ أَخْرَجَهُ الَّذِينَ كَفَرُوا ثَانِيَ اثْنَيْنِ إِذْ هُمَا فِي الْغَارِ إِذْ يَقُولُ لِصَاحِبِهِ لَا تَحْزَنْ إِنَّ اللَّهَ مَعَنَا}", "quote_es": "«Si no le auxiliáis, ya Allah le auxilió cuando los incrédulos le expulsaron, siendo el segundo de dos, cuando estaban ambos en la cueva, cuando decía a su compañero: ‹No te entristezcas, ciertamente Allah está con nosotros›».", "ref": "التوبة: 40 · Corán 9:40"}, "tasua": {"title_ar": "يوم تاسوعاء", "title_es": "Día de Tasu'a", "virtue_ar": "اليوم التاسع من محرم. يُستحب صيامه مع عاشوراء مخالفةً لليهود، كما أوصى به النبي ﷺ.", "virtue_es": "El noveno día de Muharram. Se recomienda ayunarlo junto con Ashura para diferenciarse de los judíos, tal como aconsejó el Profeta ﷺ.", "quote_ar": "«لَئِنْ بَقِيتُ إِلَى قَابِلٍ لَأَصُومَنَّ التَّاسِعَ»", "quote_es": "«Si vivo hasta el próximo año, ayunaré también el noveno [día]».", "ref": "رواه مسلم · Sahih Muslim"}, "ashura": {"title_ar": "يوم عاشوراء", "title_es": "Día de Ashura", "virtue_ar": "اليوم العاشر من محرم، نجّى الله فيه موسى وقومه من فرعون. صيامه يُكفّر ذنوب السنة الماضية.", "virtue_es": "El décimo día de Muharram; en él Allah salvó a Musa y su pueblo del Faraón. Su ayuno borra los pecados del año pasado.", "quote_ar": "«صِيَامُ يَوْمِ عَاشُورَاءَ، أَحْتَسِبُ عَلَى اللَّهِ أَنْ يُكَفِّرَ السَّنَةَ الَّتِي قَبْلَهُ»", "quote_es": "«El ayuno del día de Ashura — espero de Allah que borre los pecados del año anterior».", "ref": "رواه مسلم · Sahih Muslim"}, "mawlid": {"title_ar": "ذكرى المولد النبوي الشريف", "title_es": "Mawlid al-Nabi (Nacimiento del Profeta ﷺ)", "virtue_ar": "ذكرى ميلاد سيد الخلق محمد ﷺ. مناسبة للتذكير بسيرته العطرة وأخلاقه العظيمة والاقتداء به في كل حياتنا.", "virtue_es": "Aniversario del nacimiento del mejor de la creación, Muhammad ﷺ. Ocasión para recordar su noble biografía, su excelso carácter y seguir su ejemplo en toda nuestra vida.", "quote_ar": "{لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ لِمَنْ كَانَ يَرْجُو اللَّهَ وَالْيَوْمَ الْآخِرَ وَذَكَرَ اللَّهَ كَثِيرًا}", "quote_es": "«Ciertamente, tenéis en el Mensajero de Allah un excelente ejemplo para quien tiene esperanza en Allah y en el Último Día, y recuerda mucho a Allah».", "ref": "الأحزاب: 21 · Corán 33:21"}, "sacred_month": {"title_ar": "الأشهر الحُرُم", "title_es": "Meses Sagrados", "virtue_ar": "هذا الشهر من الأشهر الحرم الأربعة: ذو القعدة، ذو الحجة، محرم، ورجب. تعظم فيها الحسنات وتتأكد فيها الطاعات.", "virtue_es": "Este mes es uno de los cuatro Meses Sagrados: Dhul-Qi'dah, Dhul-Hijjah, Muharram y Rajab. En ellos las buenas acciones se magnifican y se enfatiza la obediencia.", "quote_ar": "{إِنَّ عِدَّةَ الشُّهُورِ عِنْدَ اللَّهِ اثْنَا عَشَرَ شَهْرًا فِي كِتَابِ اللَّهِ يَوْمَ خَلَقَ السَّمَاوَاتِ وَالْأَرْضَ مِنْهَا أَرْبَعَةٌ حُرُمٌ}", "quote_es": "«El número de meses ante Allah es doce, en el Libro de Allah, desde el día en que creó los cielos y la tierra. Cuatro de ellos son sagrados».", "ref": "التوبة: 36 · Corán 9:36"}, "regular": {"title_ar": "يوم مبارك", "title_es": "Día bendito", "virtue_ar": "كل يوم هبة من الله، اجعله عامراً بذكر الله والعمل الصالح والإحسان إلى الناس.", "virtue_es": "Cada día es un regalo de Allah; llénalo con el recuerdo de Allah, las buenas obras y la bondad hacia los demás.", "quote_ar": "«اغْتَنِمْ خَمْسًا قَبْلَ خَمْسٍ: شَبَابَكَ قَبْلَ هَرَمِكَ، وَصِحَّتَكَ قَبْلَ سَقَمِكَ، وَغِنَاكَ قَبْلَ فَقْرِكَ، وَفَرَاغَكَ قَبْلَ شُغْلِكَ، وَحَيَاتَكَ قَبْلَ مَوْتِكَ»", "quote_es": "«Aprovecha cinco antes de otras cinco: tu juventud antes de tu vejez, tu salud antes de tu enfermedad, tu riqueza antes de tu pobreza, tu tiempo libre antes de tu ocupación y tu vida antes de tu muerte».", "ref": "رواه الحاكم · Al-Hakim"}};

